  {id:'R3', sidecar_present:1, peer_auth_strict:0.472, mtls_pct:56.07, compliance_flag:0},
  {id:'R4', sidecar_present:1, peer_auth_strict:0.503, mtls_pct:42.82, compliance_flag:0},
];
const threshold = 70.0;
const warnFloor = threshold * 0.9;
const options = {
  O1: {driver:'sidecar_gap_norm', type:'reduce_risk', amount:0.12, cost:18600},
  O2: {driver:'peer_auth_gap_norm', type:'reduce_risk', amount:0.18, cost:28200},
  O3: {driver:'mtls_margin_norm', type:'improve_margin', amount:0.09, cost:32400},
};
const budget = 60000;
function classify(score) {
  if (score > threshold) return 'fail';
  if (score >= warnFloor) return 'warn';
  return 'pass';
}
function normalized(r) {
  return {
    sidecar_gap_norm: (1 - r.sidecar_present) * 100,
    peer_auth_gap_norm: (1 - r.peer_auth_strict) * 100,
    mtls_margin_norm: r.mtls_pct,
    compliance_flag_norm: r.compliance_flag * 100,
  };
}
function scoreFrom(n) {
  const weighted_sidecar_risk = n.sidecar_gap_norm;
  const weighted_peer_auth_risk = 0.6 * n.peer_auth_gap_norm;
  const weighted_mtls_credit = -0.25 * n.mtls_margin_norm;
  const score = weighted_sidecar_risk + weighted_peer_auth_risk + weighted_mtls_credit;
  return {weighted_sidecar_risk, weighted_peer_auth_risk, weighted_mtls_credit, score};
}
function round(n) { return Math.round(n * 1000000) / 1000000; }
function applyOptions(n, set) {
  const out = {...n};
  if (set.includes('O1')) out.sidecar_gap_norm *= (1 - options.O1.amount);
  if (set.includes('O2')) out.peer_auth_gap_norm *= (1 - options.O2.amount);
  if (set.includes('O3')) out.mtls_margin_norm *= (1 + options.O3.amount);
  return out;
}
function sensitivity(n, direction) {
  if (direction === 'adverse') return {
    ...n,
    sidecar_gap_norm: Math.min(100, n.sidecar_gap_norm * 1.05),
    peer_auth_gap_norm: Math.min(100, n.peer_auth_gap_norm * 1.05),
    mtls_margin_norm: Math.max(0, n.mtls_margin_norm * 0.95),
  };
  return {
    ...n,
    sidecar_gap_norm: Math.max(0, n.sidecar_gap_norm * 0.95),
    peer_auth_gap_norm: Math.max(0, n.peer_auth_gap_norm * 0.95),
    mtls_margin_norm: Math.min(100, n.mtls_margin_norm * 1.05),
  };
}
const optionSets = [[],'O1','O2','O3','O1,O2','O1,O3','O2,O3','O1,O2,O3'].map(x => Array.isArray(x) ? x : x.split(','));
const rows = records.map(r => {
  const n = normalized(r);
  const scored = scoreFrom(n);
  const baseClass = classify(scored.score);
  const advScored = scoreFrom(sensitivity(n, 'adverse'));
  const favScored = scoreFrom(sensitivity(n, 'favorable'));
  const advClass = classify(advScored.score);
  const favClass = classify(favScored.score);
  const drivers = [
    ['sidecar_gap', scored.weighted_sidecar_risk],
    ['peer_auth_gap', scored.weighted_peer_auth_risk],
  ].sort((a,b)=>b[1]-a[1]);
  return {r, n, scored, baseClass, advScore:advScored.score, advClass, favScore:favScored.score, favClass, governing: drivers[0][1] > 0 ? drivers[0][0] : 'none'};
});
