  const cost = set.reduce((sum,o)=>sum+(options[o]?.cost || 0),0);
  const allowed = cost <= budget;
  const post = rows.map(row => {
    const ns = applyOptions(row.n, set);
    const s = scoreFrom(ns).score;
    return {id: row.r.id, score: s, classification: classify(s)};
  });
  return {set: set.length ? set.join('+') : 'none', cost, allowed, fail_count: post.filter(p=>p.classification==='fail').length, warn_count: post.filter(p=>p.classification==='warn').length, total_score: post.reduce((sum,p)=>sum+p.score,0), post};
});
