  acc.sidecar_gap += row.scored.weighted_sidecar_risk;
  acc.peer_auth_gap += row.scored.weighted_peer_auth_risk;
  acc.mtls_margin_credit += row.scored.weighted_mtls_credit;
  return acc;
},{sidecar_gap:0, peer_auth_gap:0, mtls_margin_credit:0});
